227	// collectSidecarArtifacts walks .ddx/plugins/ looking for *.ddx.yaml sidecar
228	// files, then builds an Artifact for each corresponding artifact file.
229	// Files whose sidecar is missing or unreadable are silently skipped.
230	func collectSidecarArtifacts(root string) ([]*Artifact, error) {
231		pluginsDir := filepath.Join(root, ".ddx", "plugins")
232		if _, err := os.Stat(pluginsDir); os.IsNotExist(err) {
233			return nil, nil
234		}
235	
236		var out []*Artifact
237		err := filepath.WalkDir(pluginsDir, func(path string, d fs.DirEntry, err error) error {
238			if err != nil || d.IsDir() {
239				return nil
240			}
241			if !strings.HasSuffix(path, ".ddx.yaml") {
242				return nil
243			}
244	
245			// Derive artifact path by stripping the .ddx.yaml suffix.
246			artifactPath := strings.TrimSuffix(path, ".ddx.yaml")
247	
248			// Parse the sidecar.
249			data, readErr := os.ReadFile(path)
250			if readErr != nil {
251				return nil // skip unreadable sidecars
252			}
253			var sidecar ddxSidecarFile
254			if yamlErr := yaml.Unmarshal(data, &sidecar); yamlErr != nil {
255				return nil // skip malformed sidecars
256			}
257	
258			rel, relErr := filepath.Rel(root, artifactPath)
259			if relErr != nil {
260				rel = artifactPath
261			}
262	
263			id := sidecar.DDx.ID
264			if id == "" {
265				id = "sidecar:" + rel
266			}
267	
268			title := sidecar.DDx.Title
269			if title == "" {
270				title = filepath.Base(artifactPath)
271			}
272	
273			mediaType := sidecar.DDx.MediaType
274			if mediaType == "" {
275				mediaType = "application/octet-stream"
276			}
277	
278			staleness := computeSidecarStaleness(artifactPath, sidecar.DDx.GeneratedBy)
279	
280			a := &Artifact{
281				ID:        id,
282				Path:      filepath.ToSlash(rel),
283				Title:     title,
284				MediaType: mediaType,
285				Staleness: staleness,
286			}
287	
288			if sidecar.DDx.Description != "" {
289				desc := sidecar.DDx.Description
290				a.Description = &desc
291			}
292	
293			if sidecar.DDx.GeneratedBy != nil {
294				gb := sidecar.DDx.GeneratedBy
295				sourceHashMatch := false
296				if gb.SourceHash != "" {
297					if hash, hashErr := fileSHA256(artifactPath); hashErr == nil {
298						sourceHashMatch = (hash == gb.SourceHash)
299					}
300				}
301				a.GeneratedBy = &ArtifactGeneratedBy{
302					RunID:           gb.RunID,
303					PromptSummary:   gb.PromptSummary,
304					SourceHashMatch: sourceHashMatch,
305				}
306			}
307	
308			// Populate ddxFrontmatter from the raw sidecar ddx block.
309			if fm, marshalErr := json.Marshal(sidecar.DDx); marshalErr == nil {
310				s := string(fm)
311				a.DdxFrontmatter = &s
312			}
313	
314			// Populate updatedAt from artifact file mod time.
315			if info, statErr := os.Stat(artifactPath); statErr == nil {
316				ts := info.ModTime().UTC().Format(time.RFC3339)
317				a.UpdatedAt = &ts
318			}
319	
320			out = append(out, a)
321			return nil
322		})
323		if err != nil {
324			return nil, err
325		}
326		return out, nil
327	}
