357	// titleFromDoc derives a human-readable title from a docgraph document.
358	// Uses the Title field if set, otherwise derives from the path's base name.
359	func titleFromDoc(d docgraph.Document) string {
360		if d.Title != "" {
361			return d.Title
362		}
363		base := filepath.Base(d.Path)
364		// Strip extension.
365		if idx := strings.LastIndex(base, "."); idx > 0 {
366			base = base[:idx]
367		}
368		return base
369	}
