371	// Artifact is the resolver for the artifact(projectID, id) query.
372	// It returns a single artifact by ID, loading file content for text-based media types.
373	func (r *queryResolver) Artifact(ctx context.Context, projectID string, id string) (*Artifact, error) {
374		root := r.projectRoot(projectID)
375		artifacts, err := collectArtifacts(root)
376		if err != nil {
377			return nil, fmt.Errorf("collecting artifacts: %w", err)
378		}
379		for _, a := range artifacts {
380			if a.ID == id {
381				if isTextMediaType(a.MediaType) {
382					a.Content = loadArtifactContent(root, a.Path)
383				}
384				return a, nil
385			}
386		}
387		return nil, nil
388	}
389	
390	// isTextMediaType reports whether the media type has text content suitable
391	// for inline rendering (markdown, SVG, Excalidraw JSON).
392	func isTextMediaType(mt string) bool {
393		return mt == "text/markdown" || mt == "image/svg+xml" || mt == "application/vnd.excalidraw+json"
394	}
395	
396	// loadArtifactContent reads the raw file content for an artifact at the given
397	// project-relative path. Returns nil if the file cannot be read.
398	func loadArtifactContent(root, relPath string) *string {
399		absPath := filepath.Join(root, filepath.FromSlash(relPath))
400		data, err := os.ReadFile(absPath)
401		if err != nil {
402			return nil
403		}
404		s := string(data)
405		return &s
406	}
